          * Ok, we now need to push on a buffering BIO ...but not with
          * SCTP
          */
 #ifndef OPENSSL_NO_SCTP
         if (!SSL_IS_DTLS(s) || !BIO_dgram_is_sctp(SSL_get_wbio(s)))
 #endif
             if (!ssl_init_wbio_buffer(s)) {
                 goto end;
             }

